/// <summary>
/// This DP class is used to fetch all the data required on the report.
/// </summary>
[SRSReportParameterAttribute(classStr(ETGBinCocoaContract))]
class ETGBinCocoaDP extends  SRSReportDataProviderPreProcessTempDB

{
    ETGBinCocoaTmp                        ETGBinCocoaTmp;
    TransDate                             _fromDate,_ToDate;
    ETGBinJournalLine                     _ETGBinJournalLine;
    ETGLotInfoDetails                     _ETGLotInfoDetails;
    ETGBinJournalHeader                   ETGBinJournalHeader;
    ETGBinJournalLine                     ETGBinJournalLine;
    ETGBinJournalBatchDetails             ETGBinJournalBatchDetails;



}

Method.Source:
[SrsReportDataSetAttribute(tableStr(ETGBinCocoaTmp))]
public ETGBinCocoaTmp getETGBinCocoaTmp()
{
    select * from ETGBinCocoaTmp;
    return ETGBinCocoaTmp;
}

public void ProcessReport()
{
    Query                               query;
    QueryRun                            queryRun;
    QueryBuildDataSource                queryBuildDataSource, queryBuildDataSource1;
    QueryBuildDataSource                queryBuildDataSource2;
    QueryBuildRange                     queryBuildRange;
    QueryBuildRange                     queryBuildRange2;
    InventJournalTable                  InventJournalTable;
    ETGBinLotLine                       ETGBinLotLine;
    Description                         usedLot,UsedGrn,PreviousLot,PreviousGRN;

    ETGBinCocoaContract   Contract;

    Contract        = this.parmDataContract();
    List            _ItemId = new List(Types::String);
    List            _JournalId= new List(Types::String);
   // Query                   queryItemId;
   // QueryRun                queryRunItemId;
   // InventItemGroupItem     InventItemGroupItem;
   // QueryBuildDataSource    qbdsItemId;
    ListIterator             ItemIdListIterator,journalIdListIterator;
    ListEnumerator           ListEnumerator;

   // contract = this.parmDataContract() as ETGBinCocoaContract;
   // list = contract.parmItemId();
    _fromDate       = Contract.parmFromDate();
    _ToDate         = Contract.parmToDate();
    _ItemId         = Contract.parmItemId();
    _JournalId      = Contract.parmJournalId();

    query   =   new query();
    queryBuildDataSource    =   query.addDataSource(tableNum(ETGBinJournalLine));
    if(_fromDate && !_ToDate)
    {
        queryBuildRange = queryBuildDataSource.addRange(fieldNum(ETGBinJournalLine,TransDate));
        queryBuildRange.value(strFmt('>%1',queryvalue(_fromDate-1)));
    }
    if(!_fromDate && _ToDate)
    {
        queryBuildDataSource.addRange(fieldNum(ETGBinJournalLine,TransDate)).value(strFmt("<%1",queryValue(_ToDate+1)));
    }
    if(_fromDate && _ToDate)
    {
        queryBuildDataSource.addRange(fieldNum(ETGBinJournalLine,TransDate)).value(queryRange(_fromDate,_toDate));
    }
    if(_ItemId !=null)
    {
        ListEnumerator  = _ItemId.getEnumerator();
        while (ListEnumerator.moveNext())
        {
            queryBuildDataSource.addRange(fieldNum(ETGBinJournalLine,ItemId)).value(ListEnumerator.current());
        }

    }
    if(_JournalId !=null)
    {
        ListEnumerator  = _JournalId.getEnumerator();
        while (ListEnumerator.moveNext())
        {
            queryBuildDataSource.addRange(fieldNum(ETGBinJournalLine,JournalId)).value(ListEnumerator.current());
        }
    }

    queryRun    = new queryRun(query) ;
    while (queryRun.next())
    {


        _ETGBinJournalLine                              =   queryRun.get(tableNum(ETGBinJournalLine)) ;

        select ETGBinJournalHeader
            where ETGBinJournalHeader.JournalId         == _ETGBinJournalLine.JournalId;

        UsedGrn ='';
        PreviousGRN='';
        usedLot='';
        PreviousLot='';
        ETGBinCocoaTmp.clear();
        ETGBinCocoaTmp.initValue();
        ETGBinCocoaTmp.TransDate                                = _ETGBinJournalLine.TransDate;
        ETGBinCocoaTmp.JournalId                                = _ETGBinJournalLine.JournalId;
        ETGBinCocoaTmp.Description                              = ETGBinJournalHeader.Description;
        ETGBinCocoaTmp.ItemId                                   = _ETGBinJournalLine.ItemId;
        ETGBinCocoaTmp.RetailvariantId                          = _ETGBinJournalLine.RetailvariantId;
        ETGBinCocoaTmp.Configuration                            = _ETGBinJournalLine.Configuration;
        ETGBinCocoaTmp.Size                                     = _ETGBinJournalLine.Size;
        ETGBinCocoaTmp.Colour                                   = _ETGBinJournalLine.Colour;
        ETGBinCocoaTmp.Style                                    = _ETGBinJournalLine.Style;
        ETGBinCocoaTmp.SiteId                                   = _ETGBinJournalLine.SiteId;
        ETGBinCocoaTmp.Warehouse                                = _ETGBinJournalLine.Warehouse;
        ETGBinCocoaTmp.Location                                 = _ETGBinJournalLine.Location;
        ETGBinCocoaTmp.Port                                     = _ETGBinJournalLine.Port;
        ETGBinCocoaTmp.ProcessingEndDate                        = _ETGBinJournalLine.ProcessingEndDate;
        ETGBinCocoaTmp.ProcessingStartDate                      = _ETGBinJournalLine.ProcessingStartDate;
        ETGBinCocoaTmp.ProcessingPlant                          = _ETGBinJournalLine.ProcessingPlant;
        ETGBinCocoaTmp.ToBatch                                  = _ETGBinJournalLine.ToBatch;
        ETGBinCocoaTmp.BinQty                                   = _ETGBinJournalLine.BinQty;            
        if(_ETGBinJournalLine.BinQty !=0)
        {
            ETGBinCocoaTmp.BinRate                                  = round(_ETGBinJournalLine.BinRate / _ETGBinJournalLine.BinQty,0.01);
        }
        else
        {
            ETGBinCocoaTmp.BinRate =0;
        }

        ETGBinCocoaTmp.BinValue                                 = ETGBinCocoaTmp.BinQty*ETGBinCocoaTmp.BinRate;

        while select TransferJRNId from ETGBinLotLine order by InventSerialId desc
            where ETGBinLotLine.JournalId       == _ETGBinJournalLine.JournalId
            &&  ETGBinLotLine.BinJournalLine    == _ETGBinJournalLine.RecId
        {
            select  InventJournalTable
                where InventJournalTable.JournalId == ETGBinLotLine.TransferJRNId
                && InventJournalTable.Posted == noyes::Yes;
            if(InventJournalTable.RecId)
            {
                if(PreviousLot != ETGBinLotLine.InventSerialId)
                {
                    usedLot = usedLot+','+ETGBinLotLine.InventSerialId;
                }
                PreviousLot = ETGBinLotLine.InventSerialId;
            }
        }
        ETGBinCocoaTmp.CreatedLotNoUnderFGRN    = usedLot;
        ETGBinCocoaTmp.TotalFGRNWeight = _ETGBinJournalLine.FGRNQty;
        ETGBinCocoaTmp.WeightLoss   = _ETGBinJournalLine.FGRNQty - _ETGBinJournalLine.BinQty;
        if(_ETGBinJournalLine.FGRNQty!=0) 
        {
            ETGBinCocoaTmp.FGRNPrice    = round(ETGBinCocoaTmp.BinValue/_ETGBinJournalLine.FGRNQty,0.01);
        }
        if(ETGBinCocoaTmp.BinQty !=0)
        {
            ETGBinCocoaTmp.WeightLossPer    = round((ETGBinCocoaTmp.WeightLoss/ETGBinCocoaTmp.BinQty),0.01)*100;
        }
        ETGBinCocoaTmp.Waste                                    = _ETGBinJournalLine.Waste;


        select  InventJournalTable
            where InventJournalTable.JournalId == _ETGBinJournalLine.TransferJRNId
            && InventJournalTable.Posted == NoYes::Yes;
        if(InventJournalTable.RecId)
        {
            while select GRNNo from  ETGBinJournalBatchDetails order by GRNNo asc
                where ETGBinJournalBatchDetails.JournalId == _ETGBinJournalLine.JournalId
                &&  ETGBinJournalBatchDetails.BinJournalLine    == _ETGBinJournalLine.RecId
            {
                UsedGrn         = UsedGrn +','+ ETGBinJournalBatchDetails.GRNNo;
                PreviousGRN     = ETGBinJournalBatchDetails.GRNNo;
            }
        }
        ETGBinCocoaTmp.GRNUtilized      = UsedGrn;
        ETGBinCocoaTmp.insert();
    }

}
